                conditionalRequired: [
                    setPerMode: "perMode",
                    choosePerMode: "perMode"
                ]
            ],
            [
                name: "dimmer",
                family: "device",
                actions: ["setLevel", "toggle", "adjust", "fade", "stopFade", "startRaiseLower", "stopChanging", "setLevelPerMode"],
                requiredFields: [
